#include <bits/stdc++.h>
using namespace std;
int main(){int n,k;cin>>n>>k;const int MX=100001;vector<int>d(MX,-1);queue<int>q;q.push(n);d[n]=0;while(!q.empty()){int x=q.front();q.pop();if(x==k)break;for(int nx:{x-1,x+1,x*2}){if(nx>=0&&nx<MX&&d[nx]==-1){d[nx]=d[x]+1;q.push(nx);}}}cout<<d[k]<<"\n";}
